
.sense-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 5px;
}

.sense-card {
  background: var(--bg-card);
  padding: 5px 7px;
  border-left: 2px solid var(--gold-dark);
}

.sense-card:first-child {
  grid-column: 1 / -1;
}

.sense-name {
  font-size: 10px;
  color: var(--gold);
  margin-bottom: 2px;
}

.sense-desc {
  font-size: 11px;
  color: var(--text-primary);
  line-height: 1.4;
}
