
.attire-panel {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.attire-main {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 5px;
}

.attire-section {
  background: var(--bg-card);
  padding: 5px 7px;
}

.attire-label {
  font-size: 10px;
  color: var(--gold);
  margin-bottom: 2px;
}

.attire-desc {
  font-size: 11px;
  color: var(--text-primary);
  line-height: 1.4;
}

.accessory-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 4px;
}

.acc-card {
  background: var(--bg-deep);
  border: 1px solid var(--border-dim);
  padding: 4px 6px;
}

.acc-card:nth-child(4) {
  grid-column: 1 / -1;
  border-color: var(--border-gold);
}

.acc-name {
  font-size: 9px;
  color: var(--text-dim);
  margin-bottom: 1px;
}

.acc-desc {
  font-size: 10px;
  color: var(--text-primary);
  line-height: 1.35;
}
